mapper.select:
select
    invoice_number, fee_id, invoice_code, invoice_amount, tax_amount, invoice_date, invoice_type, tax_rate,
    seller_name, seller_tax_id, invoice_status, check_code, remark, create_time, update_time
from t_env_fee_invoices i


        and i.fee_id = #{feeId}



            and exists (select 1 from t_env_fees ef where ef.ent_code = #{entCode} and ef.fee_id = i.fee_id)



                and exists (select 1 from t_env_fees ef where ef.fee_id = i.fee_id and ef.ent_code in

                    #{entCode}

                )




        and i.invoice_number like concat('%', #{invoiceNumber}, '%')


        and i.invoice_date between #{invoiceStart} and #{invoiceEnd}


        and i.invoice_type = #{invoiceType}


        and i.invoice_status = #{invoiceStatus}


order by i.invoice_number desc

mapper.update:
update t_env_fee_invoices
invoice_code = #{invoiceCode}, invoice_amount = #{invoiceAmount}, tax_amount = #{taxAmount}, invoice_date = #{invoiceDate}, invoice_type = #{invoiceType}, tax_rate = #{taxRate}, seller_name = #{sellerName}, seller_tax_id = #{sellerTaxId}, invoice_status = #{invoiceStatus}, check_code = #{checkCode}, remark = #{remark},
where invoice_number = #{invoiceNumber}
